CREATE TYPE ticket_priority AS ENUM ('low','medium','high','urgent'); CREATE TYPE ticket_status AS ENUM ('new','open','pending','resolved','closed');
CREATE TABLE tickets (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),number varchar(24) NOT NULL UNIQUE,contact_id uuid NOT NULL REFERENCES contacts(id) ON DELETE RESTRICT,subject varchar(180) NOT NULL,description text NOT NULL,priority ticket_priority NOT NULL DEFAULT 'medium',status ticket_status NOT NULL DEFAULT 'new',assignee_id uuid,first_response_at timestamptz,resolved_at timestamptz,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE ticket_comments(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),ticket_id uuid NOT NULL REFERENCES tickets(id) ON DELETE CASCADE,author_id uuid NOT NULL,body text NOT NULL,internal boolean NOT NULL DEFAULT false,created_at timestamptz NOT NULL DEFAULT now());